      <n-input nSize="sm" nLabel="Small" nPlaceholder="Small" />
      <n-input nLabel="Default" nPlaceholder="Default" />
      <n-input nSize="lg" nLabel="Large" nPlaceholder="Large" />
    </div>
  `,
})
